svg.script:
(function() {
	var macaronColors = [
		'#FFB7C5', '#FFC8DD', '#FFDAE9', '#FDD5E7', '#F8C8DC', '#E8D5E4',
		'#D4E8ED', '#C5E8EE', '#B5E4E7', '#DDEFEF', '#D0EBE8', '#C4E8DA',
		'#D4E8CF', '#E0F0D4', '#E8E8C4', '#F0E8C4', '#F5E8C4', '#F8E4C4',
		'#F8DED4', '#F5E0D5', '#E8E0F0', '#DDD4E8', '#D5C8E8', '#C8D0E8', '#B5C8E8'
	];

	function getRandomColor() {
		return macaronColors[Math.floor(Math.random() * macaronColors.length)];
	}

	var containers = document.querySelectorAll('.container');
	containers.forEach(function(c) {
		c.style.background = getRandomColor();
	});

	var isAnimating = false;
	var zoomedIndex = -1;
	var zoomState = { x: 120, y: 91.3208, w: 1200, h: 917.3585 };

	// 适配可视区域并居中
	function fitToViewport() {
		var svg = document.querySelector('svg');
		var windowWidth = window.innerWidth;
		var windowHeight = window.innerHeight;
		var svgAspect = 1440 / 1100;
		var windowAspect = windowWidth / windowHeight;

		if (windowAspect > svgAspect) {
			// 窗口更宽，按高度缩放
			svg.style.height = '100vh';
			svg.style.width = 'auto';
		} else {
			// 窗口更高，按宽度缩放
			svg.style.width = '100vw';
			svg.style.height = 'auto';
		}

		// 居中
		svg.style.position = 'absolute';
		svg.style.top = '50%';
		svg.style.left = '50%';
		svg.style.transform = 'translate(-50%, -50%)';
	}

	fitToViewport();
	window.addEventListener('resize', fitToViewport);
	var animDuration = 500;

	function easeInOutCubic(t) {
		return t < 0.5 ? 4 * t * t * t : 1 - Math.pow(-2 * t + 2, 3) / 2;
	}

	for (var i = 0; i < 12; i++) {
		(function(index) {
			var originEl = document.getElementById('origin-' + index);
			var zoomEl = document.getElementById('zoom-' + index);

			var originState = {
				x: parseFloat(originEl.getAttribute('x')),
				y: parseFloat(originEl.getAttribute('y')),
				w: parseFloat(originEl.getAttribute('width')),
				h: parseFloat(originEl.getAttribute('height'))
			};

			function animateTo(el, target, onComplete) {
				var startX = parseFloat(el.getAttribute('x'));
				var startY = parseFloat(el.getAttribute('y'));
				var startW = parseFloat(el.getAttribute('width'));
				var startH = parseFloat(el.getAttribute('height'));
				var startTime = performance.now();

				function step(now) {
					var elapsed = now - startTime;
					var progress = Math.min(elapsed / animDuration, 1);
					var eased = easeInOutCubic(progress);

					var currentX = startX + (target.x - startX) * eased;
					var currentY = startY + (target.y - startY) * eased;
					var currentW = startW + (target.w - startW) * eased;
					var currentH = startH + (target.h - startH) * eased;

					el.setAttribute('x', currentX);
					el.setAttribute('y', currentY);
					el.setAttribute('width', currentW);
					el.setAttribute('height', currentH);

					if (progress < 1) {
						requestAnimationFrame(step);
					} else {
						isAnimating = false;
						if (onComplete) onComplete();
					}
				}

				isAnimating = true;
				requestAnimationFrame(step);
			}

			function zoomIn() {
				if (isAnimating || zoomedIndex !== -1) return;

				originEl.style.opacity = '0';

				setTimeout(function() {
					zoomEl.style.opacity = '1';
					zoomEl.style.pointerEvents = 'auto';
					animateTo(zoomEl, zoomState, function() {
						zoomedIndex = index;
					});
				}, 50);
			}

			function zoomOut() {
				if (isAnimating || zoomedIndex !== index) return;

				animateTo(zoomEl, originState, function() {
					zoomEl.style.opacity = '0';
					zoomEl.style.pointerEvents = 'none';
					originEl.style.opacity = '1';
					zoomedIndex = -1;
				});
			}

			originEl.addEventListener('click', zoomIn);
			zoomEl.addEventListener('click', zoomOut);
		})(i);
	}
})();
